        slow = slow.next
        fast = fast.next.next
        if slow == fast:
            return True
    return False

def twoSum(nums, target):
    prevMap = {}
    for i, n in enumerate(nums):
        diff = target - n
        if diff in prevMap: return [prevMap[diff], i]
        prevMap[n] = i

def isValid(s):
    stack = []
    mapping = {')': '(', '}': '{', ']': '['}
    for char in s:
        if char in mapping:
            top = stack.pop() if stack else '#'
            if mapping[char] != top: return False
        else:
            stack.append(char)
    return not stack

def merge(intervals):
    intervals.sort(key=lambda i: i[0])
    output = [intervals[0]]
    for start, end in intervals[1:]:
        lastEnd = output[-1][1]
        if start <= lastEnd: output[-1][1] = max(lastEnd, end)
        else: output.append([start, end])
    return output
